	for _, t := range rep.Targets {
		state := "untracked"
		if t.Tracked {
			state = fmt.Sprintf("%d managed file(s)", t.Managed)
		}
		if _, err := fmt.Fprintf(w, "target %s: %s\n", t.Target, state); err != nil {
			return err
		}
	}
	return nil
}

func sourceOf(m *manifest.Manifest) string {
	switch {
	case m.Canonical.URL != "":
