	res, err := git.Materialize(ctx, git.Input{
		CanonicalURL: canonical,
		Cache:        loc,
		PinnedSHA:    m.Canonical.Commit,
		Ref:          m.Canonical.Ref,
		Floating:     m.Canonical.Commit == "",
		Offline:      opts.Offline,
