	}
	home = filepath.Clean(absHome)

	maxHops := opts.MaxHops
	if maxHops <= 0 {
		maxHops = workspace.DefaultMaxHops
	}

	var emit []Scope
	if root, ok := findProjectRoot(absCwd, home, maxHops); ok {
		emit, err = collectEmitScopes(absCwd, root)
		if err != nil {
			return nil, err
		}
	} else if absCwd != home {
