+func cursorCompositionWouldFire(ctx context.Context, rc *runtimeContext, scopes []hierarchy.Scope, preparedLayers []preparedLayer, home string, now time.Time) bool {
+	for i := len(scopes) - 1; i >= 0; i-- {
+		sc := scopes[i]
