   187			prep, err := prepareScope(ctx, rc, sc.Root, sc.ManifestPath, sc.Level.String(), now)
   188			if err != nil {
   189				if rc != nil && rc.Logger != nil {
   190					rc.Logger.Warn("compose: cannot probe project scope for warning suppression", "path", sc.ManifestPath, "err", err)
   191				}
   192				continue
   193			}
   194			req := prep.Request
   195			applyResolvedLayers(&req, sc, preparedLayers)
   196			active := applyCursorComposition(ctx, rc, &req, prep.Manifest, req.Scope, home, now)
   197			prep.Close()
