   212		if includeUser {
   213			for i := range out {
   214				if out[i].Level == hierarchy.LevelUser {
   215					out[i].Emit = true
   216					return out
   217				}
   218			}
   219			return out
   220		}
   221	
   222		for i := len(out) - 1; i >= 0; i-- {
   223			if out[i].Level == hierarchy.LevelUser {
   224				continue
   225			}
   226			out[i].Emit = true
