   233	func materializeLayerReadOnly(ctx context.Context, rc *runtimeContext, sc hierarchy.Scope, now time.Time) (preparedLayer, bool) {
   234		m, err := manifest.LoadFile(sc.ManifestPath, manifest.LoadOptions{NonInteractive: true})
   235		if err != nil {
   236			if rc != nil && rc.Logger != nil {
   237				rc.Logger.Warn("harness: cannot load manifest", "path", sc.ManifestPath, "err", err)
   238			}
   239			return preparedLayer{}, false
   240		}
   241	
   242		root, err := fsroot.OpenWorkspaceRoot(sc.Root)
   243		if err != nil {
   244			if rc != nil && rc.Logger != nil {
   245				rc.Logger.Warn("harness: cannot open scope root", "root", sc.Root, "err", err)
   246			}
