   256		if err != nil {
   257			if rc != nil && rc.Logger != nil {
   258				rc.Logger.Warn("harness: cannot materialize scope", "path", sc.ManifestPath, "err", err)
   259			}
   260			return preparedLayer{}, false
   261		}
