   270	func layersForScope(sc hierarchy.Scope, preparedLayers []preparedLayer) []harness.Layer {
   271		var out []harness.Layer
   272		for _, pl := range preparedLayers {
   273			out = append(out, harness.Layer{
   274				Scope:     pl.Scope.Level.String(),
   275				Nodes:     pl.Materialized.Nodes,
   276				Skills:    pl.Materialized.Skills,
   277				Fragments: pl.Materialized.Fragments,
   278				SourceURL: pl.Materialized.SourceURL,
   279				Commit:    pl.Materialized.Commit,
   280			})
   281			if pl.Scope.ManifestPath == sc.ManifestPath {
   282				break
   283			}
   284		}
   285		return out
   286	}
