   288	func applyResolvedLayers(req *engine.Request, sc hierarchy.Scope, preparedLayers []preparedLayer) {
   289		layers := layersForScope(sc, preparedLayers)
   290		req.Nodes, req.Skills = harness.ResolveNodes(layers, sc.Level.String())
   291		req.Fragments = harness.ResolveFragments(layers, sc.Level.String())
