   294	// skippedUserScope returns the discovered user-level scope that is not being
   295	// emitted this run (a plain sync never writes home), when one exists.
   296	func skippedUserScope(scopes []hierarchy.Scope) (hierarchy.Scope, bool) {
   297		for _, sc := range scopes {
   298			if sc.Level == hierarchy.LevelUser && !sc.Emit {
   299				return sc, true
   300			}
   301		}
   302		return hierarchy.Scope{}, false
   303	}
