   305	// emptyRunNotice explains a hierarchy sync that discovered zero emit scopes.
   306	// Without it the run prints an empty report and exits 0 — indistinguishable
   307	// from a successful no-op, which reads as "sync doesn't do anything". Two
   308	// cases: discovery found a user-home manifest but it is read-only without
   309	// --user (the plain-sync-never-writes-home invariant), or no manifest exists
   310	// at all.
   311	func emptyRunNotice(scopes []hierarchy.Scope, cwd string) string {
   312		for _, sc := range scopes {
   313			if sc.Level == hierarchy.LevelUser && !sc.Emit {
   314				return fmt.Sprintf("manifest at %s is the user scope and a plain sync never writes to the home directory; run 'agent-sync sync --user' to sync it", sc.ManifestPath)
   315			}
   316		}
   317		return fmt.Sprintf("no .agent-sync.yaml found from %s up to the project root; run 'agent-sync init' to create one", cwd)
   318	}
