   320	// dropWarning returns ws without any warning matching (target, kind, level).
   321	// Used to suppress the user-scope Cursor rule warning when composition makes it
   322	// misleading (U5). The input slice is not mutated.
   323	func dropWarning(ws []coverage.Warning, target string, kind ir.Kind, level hierarchy.Level) []coverage.Warning {
   324		out := make([]coverage.Warning, 0, len(ws))
   325		for _, w := range ws {
   326			if w.Target == target && w.Kind == kind && w.Level == level {
   327				continue
   328			}
   329			out = append(out, w)
   330		}
   331		return out
   332	}
   333	
   334	// applyCursorComposition folds the user-scope Cursor rule layer into a
   335	// project-scope request when the project manifest opts in. It is the single
   336	// composition entry point shared by the hierarchy sync loop AND the single-scope
   337	// path (validate, watch, sync --workspace), so every command that builds a
   338	// project request sees the same composed desired state. Without this, a composed
   339	// project would report false `WouldDelete` drift under validate and lose its
   340	// composed rules under watch / --workspace sync (the owned-subdir swap wipes
   341	// anything not in the freshly-staged set).
   342	//
   343	// It mutates req in place and returns whether rules were composed. All paths are
   344	// gated on m.Compose.CursorRulesFromUser:
   345	//   - scope is not project-like: composition is project-only (D1) — warn that
   346	//     the opt-in has no effect at this scope, return false. `global` is a
   347	//     legacy project-scope alias, so it is project-like for this gate.
   348	//   - cursor not a target, or no user manifest at home: silent no-op, false.
   349	//   - user source unreadable: defer cursor (drop it from req.Targets) so a
   350	//     transient failure can't wipe previously-composed rules; warn; false.
   351	//   - rules composed: append to req.Nodes; true.
   352	func applyCursorComposition(ctx context.Context, rc *runtimeContext, req *engine.Request, m *manifest.Manifest, scope, home string, now time.Time) bool {
   353		if !m.Compose.CursorRulesFromUser {
   354			return false
   355		}
   356		if !isProjectCompositionScope(scope) {
   357			// Directory/user manifest set the opt-in; composition only applies at
   358			// project scope. Warn so it isn't a silent no-op.
   359			rc.Logger.Warn("compose: cursor-rules-from-user has no effect at this scope; set it on the project manifest", "scope", scope)
   360			return false
   361		}
   362		if !slices.Contains(req.Targets, cursorTarget) {
   363			return false
   364		}
   365		user, ok := hierarchy.UserScope(home)
   366		if !ok {
   367			return false // no user manifest to compose from
   368		}
   369		composed, failed := composeUserRules(ctx, rc, user, cursorRuleIDsOf(req.Nodes), now)
   370		switch {
   371		case failed:
   372			// The user source could not be read this run (offline URL, malformed user
   373			// manifest). Defer the Cursor sync rather than syncing project-only rules:
   374			// .cursor/rules/agent-sync/ is an owned subdir replaced by a wholesale
   375			// swap, so a project-only sync would wipe the previously-composed rules.
   376			// Dropping cursor from this run's targets leaves that subdir untouched; the
   377			// next sync that can read the user source re-syncs cursor fully. Project
   378			// cursor rule edits wait for that run — the conservative, data-preserving
   379			// choice (plan D8, transient-failure guard).
   380			req.Targets = withoutTarget(req.Targets, cursorTarget)
   381			rc.Logger.Warn("compose: deferring cursor this run — user source unreadable; existing .cursor/rules left intact",
   382				"user_manifest", user.ManifestPath)
   383			return false
   384		case len(composed) > 0:
   385			req.Nodes = append(req.Nodes, composed...)
   386			return true
   387		}
   388		return false
   389	}
   390	
   391	func isProjectCompositionScope(scope string) bool {
   392		return scope == hierarchy.LevelProject.String() || scope == manifest.ScopeGlobal
   393	}
   394	
   395	// composeUserRules materializes the user-scope manifest read-only and returns
   396	// its Cursor `rule` nodes for injection into a project sync (plan D1). The
   397	// project root remains the only write target; the user root is opened solely to
   398	// read IR.
   399	//
   400	// It is best-effort (plan D8): any failure — load, open, materialize, offline
   401	// or uncached remote source, decode — yields nil plus a warning and never
   402	// propagates. A project sync must not fail, block on a trust prompt, or hit the
   403	// network because of the user's global manifest. Remote (URL) user sources are
   404	// materialized OFFLINE (cache-only) so composition never fetches; a user who
   405	// wants a remote source composed pre-populates the cache with `sync --user`.
   406	//
   407	// projectRuleIDs is the set of `rule` ids already present in the project scope.
   408	// A user rule whose id collides is dropped (project wins, matching Cursor's
   409	// Team>Project>User precedence) with a per-id warning: the id namespace is flat,
   410	// so a coincidental clash must be observable rather than a silent data loss.
   411	//
   412	// The returned failed flag distinguishes "could not read the user source"
   413	// (load/open/materialize error → failed=true) from "read fine, produced zero
   414	// composable rules" (failed=false). The caller defers the whole Cursor sync when
   415	// failed, so a transient read failure (offline URL, malformed user manifest)
   416	// leaves the previously-composed rules in the owned .cursor/rules/ subdir intact
   417	// rather than letting the subdir swap wipe them — see the deferral at the call
   418	// site (plan D8, transient-failure guard).
   419	func composeUserRules(ctx context.Context, rc *runtimeContext, user hierarchy.Scope, projectRuleIDs map[string]struct{}, now time.Time) (nodes []ir.Node, failed bool) {
   420		// Deliberately NOT prepareScope: this reads user IR only. prepareScope also
   421		// runs DiscoverAdapters (which can launch adapter subprocesses) and builds a
   422		// full emit Request — neither is wanted for a read-only compose. Keep the
   423		// minimal LoadFile + OpenWorkspaceRoot + materialize path here (D8); do not
   424		// "consolidate" it back into prepareScope.
   425		log := rc.Logger
   426		m, err := manifest.LoadFile(user.ManifestPath, manifest.LoadOptions{NonInteractive: true})
   427		if err != nil {
   428			log.Warn("compose: cannot read user manifest", "path", user.ManifestPath, "err", err)
   429			return nil, true
   430		}

